targets.query:
// 전체 인터페이스 수 집계
// IOS + NX-OS measurement 를 union 으로 합산
// last() 로 인터페이스별 최신값 1개씩 확보 후
// group() 으로 단일 테이블 합산 → count() 로 전체 수 산출
union(
  tables: [
    from(bucket: v.bucket)
      |> range(start: -5m)
      |> filter(fn: (r) => r._measurement == "cisco_ios_interface")
      |> filter(fn: (r) => r._field == "ifOperStatus")
      |> last(),
    from(bucket: v.bucket)
      |> range(start: -5m)
      |> filter(fn: (r) => r._measurement == "cisco_nxos_interface")
      |> filter(fn: (r) => r._field == "ifOperStatus")
      |> last()
  ]
)
|> group()
|> count()

// 에러 발생 인터페이스 수
// 1) hostname + ifName 단위로 그룹화
// 2) ifInErrors + ifOutErrors 합산 (sum)
// 3) 합계 > 0 인 인터페이스만 필터
// 4) 전체 단일 그룹으로 합산 후 count
from(bucket: v.bucket)
  |> range(start: -5m)
  |> filter(fn: (r) => r._measurement == "cisco_ios_interface" or r._measurement == "cisco_nxos_interface")
  |> filter(fn: (r) => r._field == "ifInErrors" or r._field == "ifOutErrors")
  |> last()
  |> group(columns: ["hostname", "ifName"])
  |> sum()
  |> filter(fn: (r) => r._value > 0)
  |> group()
  |> count()

// 수신 BPS 계산
// derivative(): 누적 카운터의 초당 변화량(bytes/s) 계산
// *8: bytes -> bits 변환
// keep + group(hostname, ifName, _measurement) 으로 v2c/v3 중복 합산
// ifAlias 태그가 실제 데이터에 없으므로 group 에서 제거
from(bucket: v.bucket)
  |> range(start: v.timeRangeStart, stop: v.timeRangeStop)
  |> filter(fn: (r) => r._measurement == "cisco_ios_interface" or r._measurement == "cisco_nxos_interface")
  |> filter(fn: (r) => r._field == "ifHCInOctets")
  |> filter(fn: (r) => contains(value: r.hostname, set: ${hostname:json}))
  |> filter(fn: (r) => contains(value: r.ifName, set: ${interface:json}))
  |> filter(fn: (r) => contains(value: r.source, set: ${source:json}))
  |> derivative(unit: 1s, nonNegative: true)
  |> map(fn: (r) => ({ r with _value: r._value * 8.0 }))
  |> keep(columns: ["_time", "_value", "_measurement", "hostname", "ifName"])
  |> group(columns: ["_measurement", "hostname", "ifName"])
  |> aggregateWindow(every: v.windowPeriod, fn: mean, createEmpty: false)

// 인터페이스 상태 테이블
// _measurement 를 'Device Type' 으로 rename 하여 IOS/NX-OS 구분 표시
from(bucket: v.bucket)
  |> range(start: -5m)
  |> filter(fn: (r) => r._measurement == "cisco_ios_interface" or r._measurement == "cisco_nxos_interface")
  |> filter(fn: (r) => r._field == "ifOperStatus")
  |> last()
  |> keep(columns: ["_measurement", "hostname", "ifName", "ifAlias", "_value"])
  |> rename(columns: {"_value": "ifOperStatus", "_measurement": "Device Type"})
